  ('pukao-64311456-moex-00326', 'pukao-64311456', 'pukao-64311456-moex-111-146a7303', 'sub-pukao-64311456-01', NULL, 'single_choice', '對於價值觀與倫理二者關係的敘述，下列何者錯誤？', '["倫理指的是人們認為「好」的內隱或外隱的信念；價值觀指的是人們認為「對」的或「正確」的事", "社會工作倫理守則來自專業的價值基礎", "就專業倫理與價值而言，倫理乃是行動中的價值", "社會工作倫理代表和社會工作責任有關的行為期待和偏好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:35+00:00", "source_pdf_sha1": "e63444f11199", "answer_pdf_sha1": "7fe3297478eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "406", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
